==========
Absolutely! Below is a **simple but functional Space Invaders clone** using **HTML** and **vanilla JavaScript** (no frameworks).  
It features:

- **Player** (arrows to move, space to shoot)
- **Invaders** (move left/right, drop down, shoot)
- **Bullets** (player and invaders shoot)
- **Score** and **Lives**
- **Basic collision detection**
- **Restart button**

---

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Space Invaders</title>
  <style>
    body {
      background: #0a0a2a;
      display: flex;
      flex-direction: column;
      align-items: center;
      min-height: 100vh;
      margin: 0;
      font-family: 'Segoe UI', Arial, sans-serif;
    }
    #gameCanvas {
      background: #19191a;
      display: block;
      margin: 20px auto;
      width: 480px;
      height: 600px;
      border: 2px solid #444;
      box-shadow: 0 0 32px #0008;
    }
    #score, #lives, #restartBtn {
      font-size: 1.2em;
      margin-top: 18px;
      color: #fff;
      text-align: center;
      letter-spacing: 1px;
    }
    button {
      background: #4a4a4a;
      color: #fff;
      border: none;
      border-radius: 4px;
      padding: 8px 18px;
      cursor: pointer;
      font-size: 1em;
      transition: background 0.2s;
    }
    button:hover {
      background: #5a5a5a;
    }
    #gameOver {
      position: absolute;
      top: 40%;
      left: 50%;
      transform: translate(-50%, -50%);
      background: #222;
      color: #fff;
      padding: 18px 32px;
      border-radius: 8px;
      font-size: 1.3em;
      z-index: 10;
      opacity: 0;
      animation: fadeIn 0.7s;
    }
    @keyframes fadeIn {
      from { opacity: 0; }
      to   { opacity: 1; }
    }
  </style>
</head>
<body>
  <h1>🚀 Space Invaders 🚀</h1>
  <canvas id="gameCanvas" width="480" height="600"></canvas>
  <div id="score">Score: 0</div>
  <div id="lives">Lives: 3</div>
  <button id="restartBtn">Restart</button>
  <div id="gameOver" style="display:none">Game Over! <span id="gameOverScore">0</span> <br> Press R to restart.</div>

  <script>
    // --- CONFIG ---
    const W = 480, H = 600;
    const PLAYER_W = 40, PLAYER_H = 30;
    const BULLET_W = 12, BULLET_H = 12;
    const INVADER_W = 36, INVADER_H = 30;
    const GAP = 8;
    const ROWS = 5, COLS = 8;
    const INVADER_Y = 60;
    const INVADER_YINC = 30;
    const INVADER_XINC = 40;
    const PLAYER_X = W/2 - PLAYER_W/2;
    const PLAYER_Y = H-40;
    const BULLET_Y = PLAYER_Y-10;
    const BULLET_SPEED = 8;
    const INV_BUL_SPEED = 6;
    const INV_DROPS = 60;
    const MAX_BULS = 8;
    const SCORE_BASE = 10;
    const LIFE_LOSS = 1;

    // --- DOM ---
    const canvas = document.getElementById('gameCanvas');
    const ctx = canvas.getContext('2d');
    let score = 0, lives = 3;
    let gameActive = false;
    let gameOver = false;
    let invaderBullets = [];
    let playerBullets = [];
    let invaderRows = [];
    let lastShotTime = 0;

    // --- GAME STATE ---
    function resetGame() {
      score = 0;
      lives = 3;
      gameActive = true;
      gameOver = false;
      invaderBullets.length = 0;
      playerBullets.length = 0;
      invaderRows = [];
      for (let r=0; r<ROWS; ++r) {
        invaderRows.push([]);
        for (let c=0; c<COLS; ++c) {
          invaderRows[r][c] = {
            x: c*(INVADER_W+GAP),
            y: INVADER_Y + r*INVADER_YINC,
            dx: (c===0 || c===COLS-1) ? 0 : (Math.random()<0.5 ? -INV_XINC : INV_XINC),
            dy: 0,
            alive: true,
            bullet: false
          };
        }
      }
      player = {
        x: PLAYER_X,
        y: PLAYER_Y,
        dx: 0,
        dy: 0,
        alive: true,
        bullet: false,
        lastShot: 0
      };
      playerBullets.length = 0;
      invaderBullets.length = 0;
      draw();
    }

    // --- GAME LOOP ---
    function gameLoop() {
      if (!gameActive || gameOver) return;
      ctx.clearRect(0,0,W,H);

      // --- PLAYER INPUT ---
      const keys = {};
      window.addEventListener('keydown', e => keys[e.code] = true);
      window.addEventListener('keyup', e => keys[e.code] = false);

      // --- PLAYER MOVEMENT ---
      let px = player.x, py = player.y;
      if (keys['ArrowLeft'] || keys['KeyA']) px = Math.max(0, px-6);
      if (keys['ArrowRight'] || keys['KeyD']) px = Math.min(W-PLAYER_W, px+6);
      if (keys['ArrowUp'] || keys['KeyW']) py = Math.max(0, py-6);
      if (keys['ArrowDown'] || keys['KeyS']) py = Math.min(PLAYER_Y, py+6);

      // --- PLAYER SHOOT ---
      if (keys[' ']) {
        if (!player.bullet && Date.now()-player.lastShot > 120) {
          player.bullet = true;
          player.lastShot = Date.now();
          playerBullets.push({
            x: px+BULLET_W/2,
            y: BULLET_Y,
            dx: 0,
            dy: -BULLET_SPEED
          });
        }
      }

      // --- INVADER MOVEMENT ---
      let dropped = false;
      for (let r=0; r<ROWS; ++r) {
        for (let c=0; c<COLS; ++c) {
          let inv = invaderRows[r][c];
          if (!inv.alive) continue;
          inv.x += inv.dx;
          inv.y += inv.dy;

          // --- COLLISION WITH PLAYER ---
          if (
            inv.x < px+PLAYER_W &&
            inv.x+INVADER_W > px &&
            inv.y < py+PLAYER_H &&
            inv.y+INVADER_H > py
          ) {
            inv.alive = false;
            player.alive = false;
            lives--;
            if (lives<=0) {
              gameOver = true;
              document.getElementById('gameOver').style.display = 'block';
              document.getElementById('gameOverScore').textContent = score;
              return;
            }
            inv.alive = false;
            inv.alive = false;
            inv.x = inv.y = 0;
            score -= SCORE_BASE;
            continue;
          }

          // --- COLLISION WITH BULLETS ---
          for (let b of playerBullets) {
            if (
              b.x < inv.x+INVADER_W &&
              b.x+BULLET_W > inv.x &&
              b.y < inv.y+INVADER_H &&
              b.y+BULLET_H > inv.y
            ) {
              inv.alive = false;
              playerBullets.splice(playerBullets.indexOf(b),1);
              score += SCORE_BASE;
              inv.x = inv.y = 0;
              continue outerLoop; // skip rest of loop
            }
          }
          // --- INVADER DROP ---
          if (inv.y > H-100) {
            inv.alive = false;
            inv.x = inv.y = 0;
            dropped = true;
          }
          // --- SIDE WALLS ---
          if (inv.x < 0) inv.dx = Math.abs(inv.dx);
          if (inv.x > W-INVADER_W) inv.dx = -Math.abs(inv.dx);

          // --- INVADER SHOOT ---
          if (!inv.bullet && inv.y > H/2 && Math.random()<0.12) {
            inv.bullet = true;
            inv.bulletTime = Date.now();
            invaderBullets.push({
              x: inv.x+INVADER_W/2,
              y: inv.y+INVADER_H/2,
              dx: (Math.random()<0.5 ? -INV_BUL_SPEED : INV_BUL_SPEED),
              dy: INV_BUL_SPEED
            });
          }
          if (inv.bullet) {
            inv.bulletTime += 10;
            if (inv.bulletTime > Date.now()) inv.bullet = false;
          }
        }
      }

      // --- INVADER DROP ---
      if (!dropped) {
        for (let r=0; r<ROWS; ++r) {
          let droppedRow = null;
          for (let c=0; c<COLS; ++c) {
            if (!invaderRows[r][c].alive) continue;
            if (invaderRows[r][c].y > H-80) {
              droppedRow = r;
              break;
            }
          }
          if (droppedRow!==null) {
            for (let c=0; c<COLS; ++c) {
              invaderRows[droppedRow][c].dy = INV_DROPS;
            }
          }
        }
      }

      // --- BULLET MOVEMENT ---
      // Player bullets
      for (let i=playerBullets.length-1; i>=0; --i) {
        let b = playerBullets[i];
        b.y += b.dy;
        if (b.y < 0) playerBullets.splice(i,1);
        else {
          for (let ib of invaderBullets) {
            if (
              b.x < ib.x+INVADER_W &&
              b.x+BULLET_W > ib.x &&
              b.y < ib.y+INVADER_H &&
              b.y+BULLET_H > ib.y
            ) {
              // Invader hit!
              invaderBullets.splice(invaderBullets.indexOf(ib),1);
              playerBullets.splice(i,1);
              score += SCORE_BASE;
              break;
            }
          }
        }
      }

      // Invader bullets
      for (let i=invaderBullets.length-1; i>=0; --i) {
        let ib = invaderBullets[i];
        ib.y += ib.dy;
        if (ib.y > H) invaderBullets.splice(i,1);
        else {
          for (let pb of playerBullets) {
            if (
              ib.x < pb.x+BULLET_W &&
              ib.x+INVADER_W > pb.x &&
              ib.y < pb.y+BULLET_H &&
              ib.y+BULLET_H > pb.y
            ) {
              // Player hit!
              player.alive = false;
              playerBullets.splice(i,1);
              invaderBullets.splice(i,1);
              lives--;
              if (lives<=0) {
                gameOver = true;
                document.getElementById('gameOver').style.display = 'block';
                document.getElementById('gameOverScore').textContent = score;
                return;
              }
              invaderBullets.splice(i,1);
              continue;
            }
          }
        }
      }

      // --- DRAW ---
      draw();

      requestAnimationFrame(gameLoop);
    }

    // --- DRAW ---
    function draw() {
      // Background
      ctx.fillStyle = '#19191a';
      ctx.fillRect(0,0,W,H);

      // Score & Lives
      ctx.fillStyle = '#fff';
      ctx.font = 'bold 24px monospace';
      ctx.fillText(`Score: ${score}`, 20, 40);
      ctx.fillText(`Lives: ${lives}`, W-120, 40);

      // Player
      if (player.alive) {
        ctx.fillStyle = '#0f0';
        ctx.fillRect(player.x, player.y, PLAYER_W, PLAYER_H);
        ctx.strokeStyle = '#fff';
        ctx.strokeRect(player.x, player.y, PLAYER_W, PLAYER_H);

        // Player bullet
        if (player.bullet) {
          ctx.fillStyle = '#fff';
          ctx.fillRect(player.x+BULLET_W/2, BULLET_Y, BULLET_W, BULLET_H);
          ctx.strokeStyle = '#fff';
          ctx.strokeRect(player.x+BULLET_W/2, BULLET_Y, BULLET_W, BULLET_H);
          player.bullet = false;
        }
      }

      // Invaders
      for (let r=0; r<ROWS; ++r) {
        for (let c=0; c<COLS; ++c) {
          let inv = invaderRows[r][c];
          if (!inv.alive) continue;
          ctx.fillStyle = inv.bullet ? '#ff0' : '#fff';
          ctx.fillRect(inv.x, inv.y, INVADER_W, INVADER_H);
          ctx.strokeStyle = '#fff';
          ctx.strokeRect(inv.x, inv.y, INVADER_W, INVADER_H);

          // Invader bullet
          if (inv.bullet) {
            ctx.fillStyle = '#f00';
            ctx.fillRect(inv.x+INVADER_W/2, inv.y+INVADER_H/2, BULLET_W, BULLET_H);
            ctx.strokeStyle = '#f00';
            ctx.strokeRect(inv.x+INVADER_W/2, inv.y+INVADER_H/2, BULLET_W, BULLET_H);
            inv.bullet = false;
          }
        }
      }

      // --- GAME OVER TEXT ---
      if (gameOver) {
        ctx.fillStyle = '#fff';
        ctx.font = 'bold 32px monospace';
        ctx.fillText('Game Over!', W/2-80, H/2-40);
        ctx.font = 'bold 24px monospace';
        ctx.fillText(`Score: ${score}`, W/2-60, H/2+20);
        return;
      }

      // --- ANIMATION DELAY ---
      requestAnimationFrame(gameLoop);
    }

    // --- RESTART ---
    document.getElementById('restartBtn').onclick = () => {
      resetGame();
    };

    // --- START ---
    resetGame();
    requestAnimationFrame(gameLoop);

    // --- Keyboard Controls (for mobile) ---
    document.addEventListener('keydown', e => {
      if (e.code === 'KeyR' && gameOver) {
        resetGame();
        document.getElementById('gameOver').style.display = 'none';
      }
    });
  </script>
</body>
</html>
```

---

## **How to Play**

1. **Left/Right Arrow** or **A/D** – Move player left/right  
2. **Up/Down Arrow** or **W/S** – Move player up/down  
3. **Space** – Shoot a bullet  
4. **Avoid invaders!**  
5. **Destroy invaders to score points**  
6. **Lose a life if you touch an invader or their bullet**  
7. **Game Over** – All lives lost  
8. **Press R (or click Restart)** to play again

---

**You can copy-paste this into an `.html` file and open in your browser!**  
It’s a **vanilla JS implementation** (no frameworks, no images, just code).  
